mapper.select:
SELECT *
FROM recipes
WHERE is_deleted = 0

    AND category_id = #{categoryId}


    AND difficulty = #{difficulty}


    AND status = #{status}

ORDER BY created_at DESC

mapper.update:
UPDATE recipes
SET view_count = view_count + 1
WHERE id = #{id}

UPDATE recipes
SET favorite_count = favorite_count + #{increment}
WHERE id = #{id}
